patch:
zd1211rw: fix invalid signal values from device

From: Jussi Kivilinna <jussi.kivilinna@mbnet.fi>

Driver uses IEEE80211_HW_SIGNAL_UNSPEC and so signal values reported to
mac80211 should be in range 0..100. Sometimes device return out of range
values. This patch adds checks to enforce range returned from driver to
mac80211 be in 0..100 range.

Signed-off-by: Jussi Kivilinna <jussi.kivilinna@mbnet.fi>
---
 drivers/net/wireless/zd1211rw/zd_mac.c |   13 +++++++++++--
 1 files changed, 11 insertions(+), 2 deletions(-)

diff --git a/drivers/net/wireless/zd1211rw/zd_mac.c b/drivers/net/wireless/zd1211rw/zd_mac.c
index 5037c8b..ec7bcb0 100644
--- a/drivers/net/wireless/zd1211rw/zd_mac.c
+++ b/drivers/net/wireless/zd1211rw/zd_mac.c
@@ -160,6 +160,15 @@ static int zd_reg2alpha2(u8 regdomain, char *alpha2)
 	return 1;
 }

+static inline int zd_check_signal(int signal)
+{
+	if (signal < 0)
+		return 0;
+	if (signal > 100)
+		return 100;
+	return signal;
+}
+
 int zd_mac_preinit_hw(struct ieee80211_hw *hw)
 {
 	int r;
@@ -461,7 +470,7 @@ static void zd_mac_tx_status(struct ieee80211_hw *hw, struct sk_buff *skb,
 	if (i<IEEE80211_TX_MAX_RATES)
 		info->status.rates[i].idx = -1; /* terminate */

-	info->status.ack_signal = ackssi;
+	info->status.ack_signal = zd_check_signal(ackssi);
 	ieee80211_tx_status_irqsafe(hw, skb);
 }

@@ -982,7 +991,7 @@ int zd_mac_rx(struct ieee80211_hw *hw, const u8 *buffer, unsigned int length)

 	stats.freq = zd_channels[_zd_chip_get_channel(&mac->chip) - 1].center_freq;
 	stats.band = IEEE80211_BAND_2GHZ;
-	stats.signal = status->signal_strength;
+	stats.signal = zd_check_signal(status->signal_strength);

 	rate = zd_rx_rate(buffer, status);
